<?php
/*
Plugin Name: User File Upload
Description: Allows users to upload profile pictures and documents.
Version: 1.0
Author: Your Name
*/

if (!defined('ABSPATH')) {
    exit; // Exit if accessed directly.
}

function user_file_upload() {
    $upload_dir = wp_upload_dir();
    $upload_path = $upload_dir['basedir'] . '/user-files/';
    if (!file_exists($upload_path)) {
        wp_mkdir_p($upload_path);
    }

    if (isset($_FILES['user_file'])) {
        $file = $_FILES['user_file'];
        $allowed_mime_types = array('image/jpeg', 'image/png', 'application/pdf', 'application/msword', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document');

        if (in_array($file['type'], $allowed_mime_types)) {
            $file_name = sanitize_file_name($file['name']);
            $upload_file = $upload_path . '/' . $file_name;
            move_uploaded_file($file['tmp_name'], $upload_file);
            echo 'File uploaded successfully: ' . $file_name;
        } else {
            echo 'Invalid file type. Please upload an image, PDF, doc or docx file.';
        }
    }
}
add_action('init', 'user_file_upload');
?>